    fn recorder_handles_concurrent_recording() {
        // Test with multiple threads recording simultaneously
        let recorder = Arc::new(Mutex::new(TraceRecorder::new(RecorderConfig::default())));
        let handles: Vec<_> = (0..10).map(|i| {
            let recorder = recorder.clone();
            std::thread::spawn(move || {
                for j in 0..100 {
                    recorder.lock().record(TraceEvent::TaskScheduled {
                        task_id: TaskId(i * 100 + j),
                        at_tick: j,
                    });
                }
            })
        }).collect();

        for h in handles { h.join().unwrap(); }

        let trace = Arc::try_unwrap(recorder).unwrap().into_inner().finish();
        assert_eq!(trace.events().len(), 1000);
    }

    #[test]
    fn recorder_overhead_is_minimal() {
        // Benchmark: recording should not slow down execution significantly
        let start = Instant::now();
        let mut recorder = TraceRecorder::new(RecorderConfig::default());
        for i in 0..100_000 {
            recorder.record(TraceEvent::TaskScheduled { task_id: TaskId(i), at_tick: i });
        }
        let elapsed = start.elapsed();

        // Should complete in < 100ms (1μs per event)
        assert!(elapsed < Duration::from_millis(100), 
            "Recording too slow: {:?} for 100k events", elapsed);
    }
}
